import https from 'https';

const RPC = 'https://devnet.helius-rpc.com/?api-key=d4f302b4-c9aa-4632-a08c-dba50524db17';
const PROGRAM = '3iusaL6ys79DsbpweDwGhHvtjdnhAhtpyczPtMbu5Mbe';
const DEPOSIT_DISC = 'f223c68952e1f2b6';
const DEPOSIT_CREDIT_DISC = 'fb2f7578fc2c23a3';
const SETTLE_DISC = '2b25243faaf6bfe6';
const AUDIT_DISC = '32735ae4a0bee7b3';

const VAULTS = {
  old: '6i5SyF8Hx2u5MZW2JgWGhdg5CJsAKeF7UaRAd9bERDDL',
  new: '3bR3ViL4aFHda95cfL2kKBrup1L2fUgbEfW6yw1BSrfc',
};

function rpc(method, params) {
  return new Promise((resolve, reject) => {
    const body = JSON.stringify({ jsonrpc: '2.0', id: 1, method, params });
    const req = https.request(RPC, { method: 'POST', headers: { 'content-type': 'application/json', 'content-length': Buffer.byteLength(body) } }, res => {
      let chunks = [];
      res.on('data', c => chunks.push(c));
      res.on('end', () => {
        try { resolve(JSON.parse(Buffer.concat(chunks).toString())); } catch (e) { reject(e); }
      });
    });
    req.on('error', reject);
    req.write(body);
    req.end();
  });
}

async function getAllSignatures(addr) {
  const all = [];
  let before = undefined;
  while (true) {
    const params = [addr, { limit: 1000 }];
    if (before) params[1].before = before;
    const r = await rpc('getSignaturesForAddress', params);
    if (r.error) throw new Error(JSON.stringify(r.error));
    const sigs = r.result || [];
    if (sigs.length === 0) break;
    all.push(...sigs);
    if (sigs.length < 1000) break;
    before = sigs[sigs.length - 1].signature;
  }
  return all;
}

// base58 decode for instruction data
const ALPHABET = '123456789ABCDEFGHJKLMNPQRSTUVWXYZabcdefghijkmnopqrstuvwxyz';
function b58decode(s) {
  let bytes = [0];
  for (const c of s) {
    const idx = ALPHABET.indexOf(c);
    if (idx < 0) throw new Error('bad b58');
    let carry = idx;
    for (let i = 0; i < bytes.length; i++) { carry += bytes[i] * 58; bytes[i] = carry & 0xff; carry >>= 8; }
    while (carry) { bytes.push(carry & 0xff); carry >>= 8; }
  }
  for (const c of s) { if (c !== '1') break; bytes.push(0); }
  return Buffer.from(bytes.reverse());
}

async function processVault(label, vault) {
  console.log(`\n=== ${label} vault ${vault} ===`);
  const sigs = await getAllSignatures(vault);
  console.log(`total signatures touching vault_config: ${sigs.length}`);
  let depositTx = 0, depositCreditTx = 0, settleTx = 0, auditTx = 0, other = 0, failed = 0;
  let depositIxTotal = 0, depositCreditIxTotal = 0;
  // batch tx fetches
  const sigList = sigs.map(s => s.signature);
  const okSigs = sigs.filter(s => !s.err).map(s => s.signature);
  const failedCount = sigs.length - okSigs.length;
  const BATCH = 50;
  for (let i = 0; i < okSigs.length; i += BATCH) {
    const batch = okSigs.slice(i, i + BATCH);
    const reqs = batch.map((sig, idx) => ({
      jsonrpc: '2.0', id: idx, method: 'getTransaction',
      params: [sig, { encoding: 'json', commitment: 'confirmed', maxSupportedTransactionVersion: 0 }]
    }));
