      if (!tx) { other++; continue; }
      const keys = tx.transaction.message.accountKeys;
      const ixs = tx.transaction.message.instructions;
      let hasDeposit = false, hasDepositCredit = false, hasSettle = false, hasAudit = false, depCnt = 0, depCredCnt = 0;
      for (const ix of ixs) {
        const programId = keys[ix.programIdIndex];
        if (programId !== PROGRAM) continue;
        const data = b58decode(ix.data);
        const disc = data.slice(0, 8).toString('hex');
        if (disc === DEPOSIT_DISC) { hasDeposit = true; depCnt++; }
        else if (disc === DEPOSIT_CREDIT_DISC) { hasDepositCredit = true; depCredCnt++; }
        else if (disc === SETTLE_DISC) hasSettle = true;
        else if (disc === AUDIT_DISC) hasAudit = true;
      }
      if (hasDeposit) depositTx++;
      if (hasDepositCredit) depositCreditTx++;
      if (hasSettle) settleTx++;
      if (hasAudit) auditTx++;
      if (!hasDeposit && !hasDepositCredit && !hasSettle && !hasAudit) other++;
      depositIxTotal += depCnt;
      depositCreditIxTotal += depCredCnt;
    }
  }
  failed = failedCount;
  console.log(`  deposit ixs:        ${depositIxTotal}  (in ${depositTx} txs)`);
  console.log(`  deposit_with_credit:${depositCreditIxTotal}  (in ${depositCreditTx} txs)`);
  console.log(`  settle_vault txs:   ${settleTx}`);
  console.log(`  record_audit txs:   ${auditTx}`);
  console.log(`  other vault ixs:    ${other}`);
  console.log(`  failed txs:         ${failed}`);
  return { depositIxTotal, depositCreditIxTotal, settleTx, auditTx };
}

